/**
 * Processing-related type definitions for the Email Processor
 *
 * Types for email processing requests, results, and related metadata.
 */

/**
 * Request parameters for processing unclassified emails
 */
export interface ProcessUnclassifiedRequest {
  batchSize?: number;
  processingMode?: 'parallel' | 'sequential';
  gmailQuery?: string;
  maxEmails?: number;
}

/**
 * Batch processing configuration
 */
export interface BatchConfiguration {
  batchSize: number;
  processingMode: 'parallel' | 'sequential';
  gmailQuery?: string;
  maxEmails: number;
}

/**
 * Performance metrics for email processing
 */
export interface PerformanceMetrics {
  avgEmailProcessingMs: number;
  gmailFetchDurationMs: number;
  classificationDurationMs: number;
  databasePersistDurationMs: number;
  totalDurationMs: number;
  parallelBatchesExecuted: number;
  sequentialEmailsProcessed: number;
  peakMemoryUsageMB: number;
  emailsPerSecond: number;
}

/**
 * Classification summary data
 */
export interface ClassificationSummary {
  categoriesFound: Record<string, number>;
  avgConfidence: number;
  highConfidenceCount: number;
  mediumConfidenceCount: number;
  lowConfidenceCount: number;
  aiRoutingUsed: number;
  multiLabelCount: number;
}

/**
 * Integration metadata for tracking system integration
 */
export interface IntegrationMetadata {
  classificationEngineVersion: string;
  configurationVersion: string;
  pipelineStagesExecuted: number;
}

/**
 * Processing error information
 */
export interface ProcessingError {
  type: string;
  message: string;
  emailId: string;
  timestamp: Date;
}

/**
 * Processing warning information
 */
export interface ProcessingWarning {
  message: string;
}

/**
 * Result of processing unclassified emails
 */
export interface ProcessingResult {
  sessionId: string;
  totalEmailsFetched: number;
  emailsProcessed: number;
  emailsSuccessful: number;
  emailsFailed: number;
  processingStartedAt: string;
  processingCompletedAt: string;
  processingDurationMs: number;
  batchConfiguration: BatchConfiguration;
  performanceMetrics: PerformanceMetrics;
  errors: ProcessingError[];
  warnings: ProcessingWarning[];
  classificationSummary: ClassificationSummary;
  integrationMetadata: IntegrationMetadata;
}

